#include <bits/stdc++.h>
using namespace std;

const int N=25;

int n,s[N][N],f[1<<20][N];

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            scanf("%d",&s[i][j]);
    memset(f,0x3f,sizeof(f));
    f[1][1]=0;
    for(int i=0;i<1<<n;i++){
        for(int j=1;j<=n;j++){
            if(f[i][j]>1e9)
            	continue;
            for(int k=1;k<=n;k++){
                if((i>>(k-1))&1)
                    continue;
                f[i+(1<<(k-1))][k]=min(f[i+(1<<(k-1))][k],f[i][j]+s[j][k]);
            }
        }
    }
    int ans=1e9;
    for(int i=1;i<=n;i++)
        ans=min(ans,s[i][1]+f[(1<<n)-1][i]);
    printf("%d",ans);
    return 0;
}
